#include<bits/stdc++.h>
using namespace std;
int b, anssa, anssb;
int main() {
	cin >> b;
	for (int i = 1; i <= b; i++) {
		int a = i;
		int  ansa = 0, ansb = 0;
		while (a) {
			if (a & 1) ansa++;
			else ansb++;
			a >>= 1;
		}
		ansa > ansb ? anssa++ : anssb++;
	}
	cout<<anssa<<" "<<anssb;
	return 0;
}
